mapper.update:
update notification set is_read = 1
where user_id = #{userId}
  and user_type = #{userType}
  and is_read = 0

mapper.select:
select id, title, content, type, related_id, is_read, create_time
from notification
where user_id = #{userId}
  and user_type = #{userType}
  and is_read = 0
order by create_time desc

select id, title, content, type, related_id, is_read, create_time
from notification
where user_id = #{userId}
  and user_type = #{userType}
and type = #{type}
order by create_time desc

select count(*) from notification
where user_id = #{userId}
  and user_type = #{userType}
  and is_read = 0
